mapper.select:
SELECT  
  FROM  TB_MTG_PLACE_MANAGE  A
 WHERE  A.MTGRUM_ID = #{mtgPlaceId}

mapper.insert:
INSERT  INTO TB_MTG_PLACE_MANAGE
      ( MTGRUM_ID
      , MTGRUM_NM
      , OPN_BEGIN_TM
      , OPN_END_TM
      , ACEPTNC_POSBL_NMPR
      , LC_SE
      , LC_DETAIL
      , ATCH_FILE_ID
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{mtgPlaceId}
        , #{mtgPlaceNm}
        , #{opnBeginTm}
        , #{opnEndTm}
        , #{aceptncPosblNmpr}
        , #{lcSe}
        , #{lcDetail}
        , #{atchFileId}
        , #{frstRegisterId}
        , CURRENT_TIMESTAMP )

mapper.update:
UPDATE  TB_MTG_PLACE_MANAGE
   SET  MTGRUM_NM          = #{mtgPlaceNm}
      , OPN_BEGIN_TM       = #{opnBeginTm}
      , OPN_END_TM         = #{opnEndTm}
      , ACEPTNC_POSBL_NMPR = #{aceptncPosblNmpr}
      , LC_SE              = #{lcSe}
      , LC_DETAIL          = #{lcDetail}
      , LAST_UPDUSR_ID     = #{lastUpdusrId}
      , LAST_UPDT_PNTTM    = CURRENT_TIMESTAMP
 WHERE  MTGRUM_ID = #{mtgPlaceId}
